import {
  ChangeDetectionStrategy,
  Component,
  Signal,
  computed,
  forwardRef,
  input,
  model,
  output,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { collapsibleVariants, type CollapsibleVariants } from './collapsible.variants';
import { COLLAPSIBLE_CONTEXT, type CollapsibleContext } from './collapsible.tokens';

let _collapsibleCounter = 0;

@Component({
  selector: 'n-collapsible',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    '[class]': 'classes()',
    '[attr.data-state]': 'nOpen() ? "open" : "closed"',
    '[attr.data-disabled]': 'nDisabled() ? "" : null',
    'data-slot': 'root',
  },
  providers: [
    {
      provide: COLLAPSIBLE_CONTEXT,
      useFactory: (cmp: CollapsibleComponent) => cmp.context,
      deps: [forwardRef(() => CollapsibleComponent)],
    },
  ],
})
export class CollapsibleComponent {
  private readonly _id = `n-collapsible-${++_collapsibleCounter}`;

  readonly nOpen = model<boolean>(false);
  readonly nDisabled = input<boolean>(false);
  readonly nLazy = input<boolean>(false);
  readonly nVariant = input<CollapsibleVariants['nVariant']>('default');
  readonly nClass = input<string>('');

  readonly nOpenChange = output<boolean>();

  protected readonly classes = computed(() =>
    mergeClasses(collapsibleVariants({ nVariant: this.nVariant() }), this.nClass()),
  );

  private readonly _variant: Signal<'default' | 'bordered' | 'card'> = computed(
    () => this.nVariant() ?? 'default',
  );

  readonly context: CollapsibleContext = {
    isOpen: this.nOpen,
    isDisabled: this.nDisabled,
    isLazy: this.nLazy,
    variant: this._variant,
    contentId: `${this._id}-content`,
    triggerId: `${this._id}-trigger`,
    toggle: () => {
      if (this.nDisabled()) return;
      const next = !this.nOpen();
      this.nOpen.set(next);
      this.nOpenChange.emit(next);
    },
  };
}

import { ChangeDetectionStrategy, Component, ElementRef, computed, inject, input } from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { collapsibleTriggerVariants } from './collapsible.variants';
import { COLLAPSIBLE_CONTEXT } from './collapsible.tokens';

@Component({
  selector: 'n-collapsible-trigger, button[n-collapsible-trigger]',
  standalone: true,
  template: `
    <span class="flex-1 text-left"><ng-content /></span>
    <svg
      class="h-4 w-4 shrink-0 transition-transform duration-200"
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      stroke-width="2"
      stroke-linecap="round"
      stroke-linejoin="round"
      aria-hidden="true"
    >
      <path d="m6 9 6 6 6-6" />
    </svg>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    '[class]': 'classes()',
    '[attr.id]': 'ctx.triggerId',
    '[attr.role]': '_isNativeButton ? null : "button"',
    '[attr.tabindex]': '_isNativeButton ? null : (ctx.isDisabled() ? -1 : 0)',
    '[attr.aria-expanded]': 'ctx.isOpen()',
    '[attr.aria-controls]': 'ctx.contentId',
    '[attr.disabled]': 'ctx.isDisabled() ? true : null',
    '[attr.aria-disabled]': 'ctx.isDisabled() ? true : null',
    '[attr.data-state]': 'ctx.isOpen() ? "open" : "closed"',
    '[attr.data-disabled]': 'ctx.isDisabled() ? "" : null',
    'data-slot': 'trigger',
    '(click)': 'handleClick()',
    '(keydown.enter)': 'handleKeydown($event)',
    '(keydown.space)': 'handleKeydown($event)',
  },
})
export class CollapsibleTriggerComponent {
  protected readonly ctx = inject(COLLAPSIBLE_CONTEXT);

  // Native <button> handles Enter/Space activation itself; the element form
  // (n-collapsible-trigger) needs role/tabindex + manual keyboard handling.
  protected readonly _isNativeButton =
    inject(ElementRef).nativeElement.tagName === 'BUTTON';

  readonly nClass = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses(collapsibleTriggerVariants({ nVariant: this.ctx.variant() }), this.nClass()),
  );

  protected handleClick(): void {
    if (!this.ctx.isDisabled()) this.ctx.toggle();
  }

  protected handleKeydown(event: Event): void {
    // Native buttons activate via the synthesized click — avoid double-toggle.
    if (this._isNativeButton) return;
    if (!this.ctx.isDisabled()) {
      event.preventDefault();
      this.ctx.toggle();
    }
  }
}

import { ChangeDetectionStrategy, Component, computed, inject, input } from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { collapsibleContentVariants } from './collapsible.variants';
import { COLLAPSIBLE_CONTEXT } from './collapsible.tokens';

@Component({
  selector: 'n-collapsible-content',
  standalone: true,
  template: `
    <div
      class="grid transition-[grid-template-rows] duration-200 ease-out"
      [style.grid-template-rows]="ctx.isOpen() ? '1fr' : '0fr'"
    >
      <div class="overflow-hidden">
        @if (shouldRender()) {
          <div [class]="contentClasses()" data-slot="content">
            <ng-content />
          </div>
        }
      </div>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    '[attr.id]': 'ctx.contentId',
    '[attr.role]': '"region"',
    '[attr.aria-labelledby]': 'ctx.triggerId',
    '[attr.data-state]': 'ctx.isOpen() ? "open" : "closed"',
    class: 'block',
  },
})
export class CollapsibleContentComponent {
  protected readonly ctx = inject(COLLAPSIBLE_CONTEXT);

  readonly nClass = input<string>('');

  // Non-lazy content stays mounted (hidden via grid-rows 0fr + overflow-hidden)
  // so state is preserved; lazy content mounts only while open.
  protected readonly shouldRender = computed(() =>
    this.ctx.isLazy() ? this.ctx.isOpen() : true,
  );

  protected readonly contentClasses = computed(() =>
    mergeClasses(collapsibleContentVariants({ nVariant: this.ctx.variant() }), this.nClass()),
  );
}

import { InjectionToken, Signal } from '@angular/core';

export interface CollapsibleContext {
  readonly isOpen: Signal<boolean>;
  readonly isDisabled: Signal<boolean>;
  readonly isLazy: Signal<boolean>;
  readonly variant: Signal<'default' | 'bordered' | 'card'>;
  readonly contentId: string;
  readonly triggerId: string;
  toggle(): void;
}

export const COLLAPSIBLE_CONTEXT = new InjectionToken<CollapsibleContext>('CollapsibleContext');

import { cva, type VariantProps } from 'class-variance-authority';

export const collapsibleVariants = cva('w-full', {
  variants: {
    nVariant: {
      default: '',
      bordered: 'border border-border rounded-lg bg-card',
      card: 'border border-border rounded-lg bg-card shadow-sm',
    },
  },
  defaultVariants: { nVariant: 'default' },
});

export const collapsibleTriggerVariants = cva(
  'flex w-full items-center justify-between py-4 text-sm font-medium transition-all' +
    ' hover:underline focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring' +
    ' focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50' +
    ' [&[data-state=open]>svg]:rotate-180',
  {
    variants: {
      nVariant: {
        default: '',
        bordered: 'px-4',
        card: 'px-4',
      },
    },
    defaultVariants: { nVariant: 'default' },
  },
);

export const collapsibleContentVariants = cva('pb-4 pt-0 text-sm text-foreground', {
  variants: {
    nVariant: {
      default: '',
      bordered: 'px-4',
      card: 'px-4',
    },
  },
  defaultVariants: { nVariant: 'default' },
});

export type CollapsibleVariants = VariantProps<typeof collapsibleVariants>;

export { CollapsibleComponent } from './collapsible.component';
export { CollapsibleTriggerComponent } from './collapsible-trigger.component';
export { CollapsibleContentComponent } from './collapsible-content.component';
export { COLLAPSIBLE_CONTEXT } from './collapsible.tokens';
export type { CollapsibleContext } from './collapsible.tokens';
export {
  collapsibleVariants,
  collapsibleTriggerVariants,
  collapsibleContentVariants,
} from './collapsible.variants';
export type { CollapsibleVariants } from './collapsible.variants';
